from functools import cmp_to_key

def compare_containment(c1, c2):
    if c1 >= c2:
        return -1  # c1 contains c2, c1 should come before c2
    elif c2 >= c1:
        return 1   # c2 contains c1, c2 should come before c1
    else:
        return 0

